:root {
  --card-bg: #1a1a2e;
  --card-border: #2e2e50;
  --header-bg: #16213e;
  --label-color: #a78bfa;
  --label-bg: #2d1f5e;
  --room-color: #94a3b8;
  --frame-bg: #0f3460;
  --frame-border: #2e2e50;
  --art-circle: #a78bfa;
  --art-rect: #f472b6;
  --art-triangle: #34d399;
  --title-color: #f1f5f9;
  --artist-color: #a78bfa;
  --year-color: #64748b;
  --desc-color: #94a3b8;
  --tag-bg: #1e293b;
  --tag-color: #a78bfa;
  --tag-border: #2e2e50;
  --footer-bg: #16213e;
  --footer-border: #2e2e50;
  --stat-value-color: #f1f5f9;
  --stat-label-color: #64748b;
  --btn-bg: #a78bfa;
  --btn-color: #1a1a2e;
}

.gallery-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 16px;
  width: 500px;
  overflow: hidden;
}

.gallery-header {
  background: var(--header-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  border-bottom: 1px solid var(--card-border);
}

.gallery-label {
  background: var(--label-bg);
  color: var(--label-color);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  padding: 4px 10px;
  border-radius: 20px;
}

.gallery-room {
  color: var(--room-color);
  font-size: 12px;
  font-weight: 500;
}

.artwork-display {
  display: flex;
  gap: 16px;
  padding: 16px;
}

.artwork-frame {
  flex-shrink: 0;
  width: 150px;
  height: 150px;
  background: var(--frame-bg);
  border: 2px solid var(--frame-border);
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.artwork-inner {
  width: 110px;
  height: 110px;
  position: relative;
}

.art-shape {
  position: absolute;
}

.shape-circle {
  width: 60px;
  height: 60px;
  background: var(--art-circle);
  border-radius: 50%;
  top: 0;
  left: 0;
  opacity: 0.85;
}

.shape-rect {
  width: 55px;
  height: 45px;
  background: var(--art-rect);
  border-radius: 4px;
  bottom: 0;
  right: 0;
  opacity: 0.85;
}

.shape-triangle {
  width: 0;
  height: 0;
  border-left: 28px solid transparent;
  border-right: 28px solid transparent;
  border-bottom: 48px solid var(--art-triangle);
  bottom: 8px;
  left: 28px;
  opacity: 0.75;
}

.artwork-info {
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 4px;
  flex: 1;
}

.artwork-title {
  color: var(--title-color);
  font-size: 20px;
  font-weight: 700;
  margin: 0;
  line-height: 1.2;
}

.artwork-artist {
  color: var(--artist-color);
  font-size: 13px;
  font-weight: 600;
  margin: 0;
}

.artwork-year {
  color: var(--year-color);
  font-size: 11px;
  font-weight: 500;
  margin: 0;
}

.artwork-desc {
  color: var(--desc-color);
  font-size: 12px;
  line-height: 1.5;
  margin: 4px 0 0 0;
}

.artwork-tags {
  display: flex;
  gap: 6px;
  margin-top: 8px;
  flex-wrap: wrap;
}

.tag {
  background: var(--tag-bg);
  color: var(--tag-color);
  border: 1px solid var(--tag-border);
  font-size: 10px;
  font-weight: 600;
  padding: 3px 8px;
  border-radius: 20px;
}

.gallery-footer {
  background: var(--footer-bg);
  border-top: 1px solid var(--footer-border);
  display: flex;
  align-items: center;
  padding: 12px 16px;
  gap: 0;
}

.footer-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
}

.stat-value {
  color: var(--stat-value-color);
  font-size: 15px;
  font-weight: 700;
  line-height: 1.2;
}

.stat-label {
  color: var(--stat-label-color);
  font-size: 10px;
  font-weight: 500;
  margin-top: 2px;
}

.enquire-btn {
  background: var(--btn-bg);
  color: var(--btn-color);
  border: none;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 700;
  padding: 8px 20px;
  cursor: pointer;
  margin-left: 8px;
}
